import React, { useState } from 'react';
import AdminNavbar from '../components/AdminNavbar';
import AdminSidebar from '../components/AdminSidebar';

const AdminDashboard = () => {
  const [activeRentals] = useState(12);
  const [vehiclesAvailable] = useState(28);
  const [upcomingReservations] = useState(7);
  const [totalEarnings] = useState(25600);

  return (
    <div style={styles.container}>
      <AdminNavbar />
      <AdminSidebar />
      
      <main style={styles.mainContent}>
        <div style={styles.contentWrapper}>
          <h2 style={styles.pageTitle}>Dashboard Summary</h2>

          {/* Cards Row */}
          <div style={styles.cardsRow}>
            <div style={styles.card} aria-label={`Active Rentals ${activeRentals}`}>
              <div style={styles.cardTitle}>Active Rentals</div>
              <div style={styles.cardValue}>{activeRentals}</div>
              <div style={styles.cardIcon}>
                <svg viewBox="0 0 24 24" fill="#2b46ef" width="32" height="24">
                  <path d="M4 6h16v9h2v1h-1v4a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1v-4H2v-1h2V6Zm1 2v7h4v-7H5Zm12 7v-7h-4v7h4Zm-9-5h1v3h-1v-3Zm6 0h1v3h-1v-3Z"/>
                </svg>
              </div>
            </div>
            
            <div style={styles.card} aria-label={`Vehicles Available ${vehiclesAvailable}`}>
              <div style={styles.cardTitle}>Vehicles Available</div>
              <div style={styles.cardValue}>{vehiclesAvailable}</div>
              <div style={styles.cardIcon}>
                <svg viewBox="0 0 24 24" fill="#ff7a1e" width="32" height="24">
                  <path d="M3 11v6a3 3 0 0 0 6 0v-6H3Zm14 0v6a3 3 0 0 0 6 0v-6h-6ZM3 18v2h18v-2H3Z"/>
                </svg>
              </div>
            </div>
            
            <div style={styles.card} aria-label={`Upcoming Reservations ${upcomingReservations}`}>
              <div style={styles.cardTitle}>Upcoming Reservations</div>
              <div style={styles.cardValue}>{upcomingReservations}</div>
              <div style={styles.cardIcon}>
                <svg viewBox="0 0 24 24" fill="#2bc534" width="32" height="24">
                  <path d="M7 11h10M7 15h7m-2-7V3H9v4H7a1 1 0 0 0-1 1v13h12V7a1 1 0 0 0-1-1h-2V3h-2v4Z"/>
                </svg>
              </div>
            </div>
            
            <div style={{...styles.card, ...styles.cardEarnings}} aria-label={`Total Earnings ${totalEarnings} Philippine Peso`}>
              <div style={{...styles.cardTitle, marginBottom: '5px'}}>Php</div>
              <div style={styles.cardEarningsValue}>{totalEarnings.toLocaleString()}.00</div>
            </div>
          </div>

          {/* Stats and Recent Bookings */}
          <div style={styles.statsSection}>
            <section style={styles.statsContainer} aria-label="Rental Statistics Section">
              <div style={styles.statsHeader}>
                <h3 style={styles.statsTitle}>Rental Statistics</h3>
                <div style={styles.btnGroup} role="tablist" aria-label="Toggle rental statistics view">
                  <button style={{...styles.btn, ...styles.btnWeekly, ...styles.btnActive}} role="tab" aria-selected="true" tabIndex="0">Weekly</button>
                  <button style={{...styles.btn, ...styles.btnMonthly}} role="tab" aria-selected="false" tabIndex="-1">Monthly</button>
                </div>
              </div>
              <div style={styles.chartWrapper}>
                <canvas id="rentalChart" aria-hidden="true"></canvas>
              </div>
            </section>

            <aside style={styles.recentBookings} aria-label="Recent Bookings Summary">
              <h3 style={styles.recentTitle}>Recent Bookings</h3>
              <div style={styles.bookingDetails} aria-live="polite" aria-atomic="true" aria-relevant="text">
                Booking <span style={styles.bookingId} tabIndex="0" role="link" aria-describedby="descBookingBR2510a">BR2510a</span>
                <span style={styles.bookingValue}>Php 2,500.00</span>
                <div id="descBookingBR2510a" className="sr-only">Booking ID BR2510a amount Php 2,500.00</div>
                <div style={styles.subItem}><span>Jhon Carl</span></div>
                <div style={styles.subItem}>Payment Method: Credit Card</div>
                <div style={styles.subItem}>Type of Vehicle: Ford Ranger</div>
                <div style={styles.subItem}>Date of Pickup: May 5, 2026 | 10:00 AM</div>

                <div style={styles.bookingBtnGroup}>
                  <button style={styles.btnReject} type="button" aria-label="Reject booking BR2510a">Reject Booking</button>
                  <button style={styles.btnConfirm} type="button" aria-label="Confirm booking BR2510a">Confirm Booking</button>
                </div>
              </div>
            </aside>
          </div>

          {/* Info Row */}
          <section style={styles.infoRow} aria-label="Car rental benefits">
            <div style={styles.infoBox}>
              <svg viewBox="0 0 64 64" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinejoin="round" strokeLinecap="round" aria-hidden="true" focusable="false" style={styles.infoSvg}>
                <path d="M9 52h46M12 44h40M16 36h32M20 28h24M24 20h16" />
              </svg>
              <div style={styles.infoText}>
                <strong>Affordable Rates</strong>
                <span>Great prices on all vehicle types</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 50 50" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" aria-hidden="true" focusable="false" style={styles.infoSvg}>
                <circle cx="25" cy="25" r="24" />
                <path d="M21 18v9l6 3" />
                <path d="M25 31v-8" />
                <path d="M15 15h20" />
                <path d="M12 38h10" />
                <path d="M33 38h7" />
              </svg>
              <div style={styles.infoText}>
                <strong>Safety &amp; Security</strong>
                <span>Well-maintained and safe rental cars</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 22 22" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" aria-hidden="true" focusable="false" style={styles.infoSvg}>
                <path d="M2 16v1a5 5 0 0 0 10 0v-1" />
                <path d="M17 12v-6a5 5 0 0 0-10 0v6" />
                <line x1="0" y1="7" x2="22" y2="7" />
                <line x1="4" y1="12" x2="18" y2="12" />
                <line x1="7" y1="16" x2="15" y2="16" />
              </svg>
              <div style={styles.infoText}>
                <strong>Easy Booking</strong>
                <span>Quick and Hassle free online reservations</span>
              </div>
            </div>
          </section>
        </div>
      </main>

      {/* Chart.js */}
      <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
      <script dangerouslySetInnerHTML={{
        __html: `
          const ctx = document.getElementById('rentalChart');
          if (ctx) {
            const chartCtx = ctx.getContext('2d');
            const weeklyData = {
              labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
              datasets: [
                {
                  label: '% Rental 1',
                  type: 'line',
                  data: [7, 14, 12, 16, 29, 20, 32],
                  borderColor: '#2846e3',
                  backgroundColor: '#2846e3',
                  fill: false,
                  tension: 0.35,
                  pointRadius: 5,
                  yAxisID: 'y',
                },
                {
                  label: '% Rental 2',
                  type: 'line',
                  data: [2, 10, 6, 16, 12, 20, 16],
                  borderColor: '#d18029',
                  backgroundColor: '#d18029',
                  fill: false,
                  tension: 0.35,
                  pointRadius: 5,
                  yAxisID: 'y',
                },
                {
                  label: 'Rental Volume',
                  type: 'bar',
                  data: [1, 4, 8, 9, 15, 12, 20],
                  backgroundColor: '#acc8ff',
                  borderRadius: 5,
                  yAxisID: 'y1',
                }
              ]
            };

            const config = {
              type: 'bar',
              data: weeklyData,
              options: {
                responsive: true,
                maintainAspectRatio: false,
                interaction: { mode: 'nearest', intersect: false },
                scales: {
                  y: {
                    type: 'linear',
                    position: 'left',
                    min: 0,
                    max: 40,
                    ticks: { stepSize: 5, color: '#2846e3', font: { weight: 'bold' } },
                    grid: { color: '#c7d2f9' }
                  },
                  y1: {
                    type: 'linear',
                    position: 'right',
                    min: 0,
                    max: 30,
                    grid: { drawOnChartArea: false },
                    ticks: { stepSize: 5, color: '#acc8ff', font: { weight: 'bold' } }
                  }
                },
                plugins: {
                  legend: { labels: { font: { weight: 'bold', size: 14 } } },
                  tooltip: { mode: 'index', intersect: false, backgroundColor: '#2a46e7', titleFont: { weight: 'bold' }, bodyFont: { weight: '600' } }
                }
              }
            };

            new Chart(chartCtx, config);
          }
        `
      }} />

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inria+Serif&display=swap');
        
        * {
          box-sizing: border-box;
        }
        
        body {
          margin: 0;
          font-family: 'Inria Serif', serif;
        }
        
        .sr-only {
          position: absolute !important;
          width: 1px !important;
          height: 1px !important;
          padding: 0 !important;
          margin: -1px !important;
          overflow: hidden !important;
          clip: rect(0,0,0,0) !important;
          border: 0 !important;
        }
      `}</style>
    </div>
  );
};

